#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int a[n], b[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &a[i], &b[i]);
    }
    int ans = 0;
    for (int i = 0; i < n - 1; i++) {
        ans += (a[i] > b[i] ? a[i] - b[i] : 0);
    }
    printf("%d\n", ans);
    return 0;
}

