import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] a = new int[n];
        int[] b = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = scanner.nextInt();
            b[i] = scanner.nextInt();
        }
        int ans = 0;
        for (int i = 0; i < n - 1; i++) {
            ans += (a[i] > b[i] ? a[i] - b[i] : 0);
        }
        System.out.println(ans);
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let a = [];
let b = [];
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        let input = line.split(' ').map(num => parseInt(num));
        a.push(input[0]);
        b.push(input[1]);
    }
    i++;
    if (i === n + 1) {
        let ans = 0;
        for (let j = 0; j < n - 1; j++) {
            ans += Math.max(0, a[j] - b[j]);
        }
        console.log(ans);
        readline.close();
    }
});
